import polars as pl

def build_pipeline(path: str, seed: int = 42) -> pl.LazyFrame:
    return (
        pl.scan_parquet(path)
        .filter(pl.col("score") > 0.5)
        .with_columns(pl.col("score").rank().alias("rank"))
        .sort("rank")  # explicit order for reproducibility
    )

def sample_reproducible(df: pl.DataFrame, n: int = 100) -> pl.DataFrame:
    return df.sample(n=n, seed=42)

# Single collect at the boundary
result = build_pipeline("data/features.parquet").collect()
sampled = sample_reproducible(result)
